class Solution(object):
    def countHillValley(self, nums):
        count = 0
        for i in range(1, len(nums) - 1):
            left_val = nums[i-1]
            mid_val = nums[i]
            right_idx = i + 1
            while right_idx < len(nums) and nums[right_idx] == mid_val:
                right_idx += 1
            if right_idx == len(nums):
                break
            right_val = nums[right_idx]
            if (mid_val > left_val and mid_val > right_val) or (mid_val < left_val and mid_val < right_val):
                count += 1
        return count
